// This node receives config from EITHER:
// A) Master (via $('Dual-Trigger Pruefung') TRUE branch -> body.config)
// B) Sheet reads (via FALSE branch -> Konfig + Accounts tabs)

// Try to get from webhook body first (Master call)
const webhookData = $('Webhook Trigger').first().json.body;

let config = {};
let accounts = [];

if (webhookData && webhookData.config) {
  // Master provided config
  config = webhookData.config;
  accounts = webhookData.accounts || [];
} else {
  // Standalone: build config from Sheet rows
  const konfigRows = $('Konfig aus Sheet lesen').all();
  for (const row of konfigRows) {
    const key = row.json['Einstellung'] || row.json['einstellung'];
    const val = row.json['Wert'] || row.json['wert'];
    if (key) config[key] = val;
  }

  // Parse accounts from Sheet
  const accountRows = $('Accounts aus Sheet lesen').all();
  accounts = accountRows
    .map(r => r.json)
    .filter(a => String(a['Aktiv'] || a['aktiv']).toUpperCase() === 'TRUE');
}

// Parse active_platforms from comma-separated string
const activePlatforms = (config.active_platforms || '')
  .split(',')
  .map(p => p.trim().toLowerCase())
  .filter(p => p.length > 0);

// Calculate calendar week
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const days = Math.floor((now - startOfYear) / (24 * 60 * 60 * 1000));
const calendarWeek = Math.ceil((days + startOfYear.getDay() + 1) / 7);

return [{
  json: {
    config,
    accounts,
    activePlatforms,
    calendarWeek,
    year: now.getFullYear(),
    projectName: config.project_name || 'unknown',
    timestamp: now.toISOString()
  }
}];

// Creates 1 item per active platform for SplitInBatches processing
const input = $input.first().json;
const { config, accounts, activePlatforms, calendarWeek, year, projectName, timestamp } = input;

// Initialize global static data for result collection
const staticData = $getWorkflowStaticData('global');
staticData.results = [];
staticData.errors = [];
staticData.startedAt = new Date().toISOString();

const platformItems = [];

for (const platform of activePlatforms) {
  // Find matching account
  const account = accounts.find(a => 
    (a['Plattform'] || a['plattform'] || '').toLowerCase() === platform
  );

  if (!account) {
    staticData.errors.push({
      platform,
      error: 'Kein Account in Plattform-Accounts Tab gefunden',
      timestamp: new Date().toISOString()
    });
    continue;
  }

  platformItems.push({
    json: {
      platform,
      accountName: account['Account-Name'] || account['account_name'] || '',
      accountId: account['Account-ID'] || account['account_id'] || '',
      accountUrl: account['Account-URL'] || account['account_url'] || '',
      apifyActorId: account['Apify Actor ID'] || account['apify_actor_id'] || '',
      calendarWeek,
      year,
      projectName,
      config,
      timestamp
    }
  });
}

if (platformItems.length === 0) {
  return [{ json: { _empty: true, message: 'Keine aktiven Plattformen gefunden' } }];
}

return platformItems;

const staticData = $getWorkflowStaticData('global');
const platformInfo = $('Plattform Switch').first().json;

try {
  const items = $input.all();

  // Check if Apify returned error (continueRegularOutput)
  if (!items || items.length === 0 || items[0].json?.error) {
    throw new Error(items[0]?.json?.error || 'Keine Daten von Apify erhalten');
  }

  // Instagram profile scraper returns profile + posts
  const profile = items.find(i => i.json.followersCount !== undefined)?.json || items[0].json;
  const posts = items.filter(i => i.json.likesCount !== undefined).map(i => i.json);

  // Sort posts by engagement
  const sortedPosts = [...posts].sort((a, b) => 
    ((b.likesCount || 0) + (b.commentsCount || 0)) - 
    ((a.likesCount || 0) + (a.commentsCount || 0))
  );

  const topPost = sortedPosts[0];
  const worstPost = sortedPosts[sortedPosts.length - 1];

  const totalLikes = posts.reduce((s, p) => s + (p.likesCount || 0), 0);
  const totalComments = posts.reduce((s, p) => s + (p.commentsCount || 0), 0);
  const totalShares = posts.reduce((s, p) => s + (p.sharesCount || 0), 0);
  const totalViews = posts.reduce((s, p) => s + (p.videoViewCount || p.viewCount || 0), 0);
  const followers = profile.followersCount || 0;
  const engagementRate = followers > 0 
    ? ((totalLikes + totalComments) / (posts.length * followers) * 100) 
    : 0;

  const result = {
    platform: 'instagram',
    calendarWeek: platformInfo.calendarWeek,
    year: platformInfo.year,
    projectName: platformInfo.projectName,
    followers,
    followerGrowth: 0,
    postsPublished: posts.length,
    impressions: 0,
    reach: 0,
    likes: totalLikes,
    comments: totalComments,
    shares: totalShares,
    engagementRate: Math.round(engagementRate * 10000) / 10000,
    topPostUrl: topPost?.url || '',
    topPostEngagement: topPost ? (topPost.likesCount || 0) + (topPost.commentsCount || 0) : 0,
    worstPostUrl: worstPost?.url || '',
    worstPostEngagement: worstPost ? (worstPost.likesCount || 0) + (worstPost.commentsCount || 0) : 0,
    videoViews: totalViews,
    storyViews: null,
    linkClicks: null,
    status: 'ok'
  };

  staticData.results.push(result);
  return [{ json: { ...result, _parsed: true } }];

} catch (error) {
  const errEntry = {
    platform: 'instagram',
    calendarWeek: platformInfo.calendarWeek,
    year: platformInfo.year,
    projectName: platformInfo.projectName,
    error: error.message,
    status: 'error'
  };
  staticData.errors.push(errEntry);
  return [{ json: errEntry }];
}

