const staticData = $getWorkflowStaticData('global');
const platformInfo = $('Plattform Switch').first().json;

try {
  const items = $input.all();

  if (!items || items.length === 0 || items[0].json?.error) {
    throw new Error(items[0]?.json?.error || 'Keine Daten von Apify erhalten');
  }

  // Twitter scraper returns user profile + tweets
  const userData = items.find(i => i.json.user?.followersCount !== undefined || i.json.followersCount !== undefined)?.json;
  const tweets = items.filter(i => i.json.likeCount !== undefined || i.json.retweetCount !== undefined).map(i => i.json);

  const followers = userData?.user?.followersCount || userData?.followersCount || 0;

  const totalLikes = tweets.reduce((s, t) => s + (t.likeCount || 0), 0);
  const totalRetweets = tweets.reduce((s, t) => s + (t.retweetCount || 0), 0);
  const totalReplies = tweets.reduce((s, t) => s + (t.replyCount || 0), 0);
  const totalImpressions = tweets.reduce((s, t) => s + (t.impressionCount || t.viewCount || 0), 0);

  const sortedTweets = [...tweets].sort((a, b) => {
    const engA = (a.likeCount || 0) + (a.retweetCount || 0) + (a.replyCount || 0);
    const engB = (b.likeCount || 0) + (b.retweetCount || 0) + (b.replyCount || 0);
    return engB - engA;
  });

  const topTweet = sortedTweets[0];
  const worstTweet = sortedTweets[sortedTweets.length - 1];

  const engagementRate = followers > 0 && tweets.length > 0
    ? ((totalLikes + totalRetweets + totalReplies) / (tweets.length * followers) * 100)
    : 0;

  const result = {
    platform: 'x_twitter',
    calendarWeek: platformInfo.calendarWeek,
    year: platformInfo.year,
    projectName: platformInfo.projectName,
    followers,
    followerGrowth: 0,
    postsPublished: tweets.length,
    impressions: totalImpressions,
    reach: 0,
    likes: totalLikes,
    comments: totalReplies,
    shares: totalRetweets,
    engagementRate: Math.round(engagementRate * 10000) / 10000,
    topPostUrl: topTweet?.url || topTweet?.tweetUrl || '',
    topPostEngagement: topTweet ? (topTweet.likeCount || 0) + (topTweet.retweetCount || 0) + (topTweet.replyCount || 0) : 0,
    worstPostUrl: worstTweet?.url || worstTweet?.tweetUrl || '',
    worstPostEngagement: worstTweet ? (worstTweet.likeCount || 0) + (worstTweet.retweetCount || 0) + (worstTweet.replyCount || 0) : 0,
    videoViews: null,
    storyViews: null,
    linkClicks: null,
    status: 'ok'
  };

  staticData.results.push(result);
  return [{ json: { ...result, _parsed: true } }];

} catch (error) {
