    calendarWeek: platformInfo.calendarWeek,
    year: platformInfo.year,
    projectName: platformInfo.projectName,
    error: error.message,
    status: 'error'
  };
  staticData.errors.push(errEntry);
  return [{ json: errEntry }];
}

// Simply pass through -- the parsed result has already been stored
// in staticData by the Parse nodes. This node serves as a
// convergence point before looping back to SplitInBatches.
const item = $input.first().json;
return [{ json: item }];

// Retrieve all collected results from static data
const staticData = $getWorkflowStaticData('global');
const results = staticData.results || [];
const errors = staticData.errors || [];

// Build normalized items for Supabase + Sheets
const normalizedItems = results
  .filter(r => r.status === 'ok')
  .map(r => ({
    json: {
      project_name: r.projectName,
      platform: r.platform,
      calendar_week: r.calendarWeek,
      year: r.year,
      followers: r.followers || 0,
      follower_growth: r.followerGrowth || 0,
      posts_published: r.postsPublished || 0,
      impressions: r.impressions || 0,
      reach: r.reach || 0,
      likes: r.likes || 0,
      comments: r.comments || 0,
      shares: r.shares || 0,
      engagement_rate: r.engagementRate || 0,
      top_post_url: r.topPostUrl || '',
      top_post_engagement: r.topPostEngagement || 0,
      worst_post_url: r.worstPostUrl || '',
      worst_post_engagement: r.worstPostEngagement || 0,
      video_views: r.videoViews || null,
      story_views: r.storyViews || null,
      link_clicks: r.linkClicks || null,
      collected_at: new Date().toISOString(),
      data_source: 'wf1_performance_collector'
    }
  }));

// Store summary for response and run log
staticData.normalizedCount = normalizedItems.length;
staticData.finishedAt = new Date().toISOString();

if (normalizedItems.length === 0) {
  return [{ json: { _empty: true, message: 'Keine Daten zum Schreiben', errors } }];
}

return normalizedItems;

const staticData = $getWorkflowStaticData('global');
const results = staticData.results || [];
const errors = staticData.errors || [];

const platformsOk = results.filter(r => r.status === 'ok').map(r => r.platform);
const platformsError = errors.map(e => e.platform);

const startedAt = staticData.startedAt || new Date().toISOString();
const finishedAt = new Date().toISOString();
const startMs = new Date(startedAt).getTime();
const endMs = new Date(finishedAt).getTime();
const durationSeconds = Math.round((endMs - startMs) / 1000 * 100) / 100;

const status = errors.length === 0 
  ? 'success' 
  : platformsOk.length > 0 
    ? 'partial_success' 
    : 'error';

return [{
  json: {
    workflow_name: 'WF1 Performance Collector',
    workflow_id: $workflow.id || '',
    execution_id: $execution.id || '',
    project_name: results[0]?.projectName || 'unknown',
    started_at: startedAt,
    finished_at: finishedAt,
    duration_seconds: durationSeconds,
    status,
    platforms_ok: platformsOk,
    platforms_error: platformsError,
    error_details: errors.length > 0 ? JSON.stringify(errors) : null,
    items_processed: staticData.normalizedCount || 0
  }
}];

const staticData = $getWorkflowStaticData('global');
const results = staticData.results || [];
const errors = staticData.errors || [];

const platformsOk = results.filter(r => r.status === 'ok').map(r => r.platform);
const platformsError = errors.map(e => e.platform);

// Clean up static data
delete staticData.results;
delete staticData.errors;
delete staticData.startedAt;
delete staticData.finishedAt;
delete staticData.normalizedCount;

return [{
  json: {
    success: errors.length === 0,
    workflow: 'WF1 Performance Collector',
    data: {
      platformsCollected: platformsOk,
      platformsFailed: platformsError,
      totalPlatforms: platformsOk.length + platformsError.length,
      successCount: platformsOk.length,
      errorCount: platformsError.length
    },
    errors: errors.length > 0 ? errors : null,
    timestamp: new Date().toISOString()
  }
}];
